"""Expand the ecommerce product catalog with ~80 additional products."""
import json, os

PROJ = os.path.join("D:", os.sep, "github", "tripmind", "trad_rag")
DATA_FILE = os.path.join(PROJ, "data", "ecommerce_products", "products.json")

def S(sid, props, price):
    return {"sku_id": sid, "properties": props, "price": price}

def F(q, a):
    return {"question": q, "answer": a}

def R(n, r, c):
    return {"nickname": n, "rating": r, "content": c}

def build(cat_cn, cat_key, items):
    res = []
    for it in items:
        skus = it[4]
        rvs = it[7]
        prices = [s["price"] for s in skus]
        avg = round(sum(r["rating"] for r in rvs) / len(rvs), 2)
        # Handle both "026" (needs prefix) and "p_clothes_026" (already full) formats
        raw_pid = it[0]
        pid = raw_pid if raw_pid.startswith("p_") else f"p_{cat_key}_{raw_pid}"
        res.append({
            "product_id": pid, "title": it[1], "brand": it[2],
            "category": cat_cn, "category_key": cat_key, "sub_category": it[3],
            "base_price": prices[0], "min_price": min(prices), "max_price": max(prices),
            "currency": "CNY", "stock_status": "available_for_demo", "stock_quantity": None,
            "skus": skus, "description": it[5], "faqs": it[6], "reviews": rvs,
            "review_count": len(rvs), "rating_avg": avg, "tags": it[8],
            "best_for": it[9], "not_good_for": it[10], "supported_scenarios": it[11],
            "metadata": {"source": "agent_expansion_v1", "source_image_path": ""},
            "image_path": "", "image_url": "",
        })
    return res

