    I.append(("p_food_030","嘉士利薄脆饼干早餐饼干酥脆咸味休闲零食大礼包","嘉士利","饼干",[S("s_p_food_030_1",{"规格":"180g*3包"},25),S("s_p_food_030_2",{"规格":"800g 礼盒装"},49),S("s_p_food_030_3",{"规格":"1.5kg 家庭超值装"},69)],"嘉士利薄脆饼干经典国货品牌薄脆口感酥脆可口。多种口味芝麻香葱原味等。低油低糖配方老少皆宜。适合早餐搭配牛奶下午茶零食送礼。",[F("嘉士利和太平苏打比怎么样？","嘉士利更薄更脆口感更轻盈。太平苏打更厚实酥脆。看个人喜好。"),F("适合减肥期吃吗？","薄脆饼干热量约450千卡/100g比曲奇低但不宜多吃。每次5-10片为宜。"),F("保质期多久？","12个月密封保存。开封后容易受潮建议用密封夹封好尽快食用。")],[R("国货粉丝",5,"嘉士利薄脆从小吃到大！酥脆好吃不油腻。69的1.5kg太划算了全家吃。"),R("张明",4,"性价比很高的饼干。口感酥脆味道好。但包装比较简单不够精致。"),R("李萌",3,"还行但口味比较单一。吃多了会觉得腻。搭配茶水更好。"),R("王大力",5,"给爸妈买的他们特别喜欢。薄脆不硬老人也能吃。国货品质好。"),R("陈花",4,"香葱味最好吃！酥脆咸香配茶完美。25块3包太划算了。")],["嘉士利","食品饮料","饼干","薄脆","国货","酥脆","零食","180g","800g","1.5kg"],["早餐搭配","下午茶","家庭零食","送礼"],["受潮易变软","控糖人群"],["daily_snack","office_work","gift_selection"]))

    I.append(("p_food_031","丹麦蓝罐曲奇饼干礼盒装进口黄油曲奇节日送礼908g","丹麦蓝罐","饼干",[S("s_p_food_031_1",{"规格":"454g"},89),S("s_p_food_031_2",{"规格":"908g"},168)],"丹麦蓝罐曲奇丹麦原装进口100%天然黄油制作不添加人造黄油。5种经典造型口感酥脆黄油香浓郁。精美铁罐包装送礼首选。适合节日送礼长辈探望和下午茶。",[F("丹麦蓝罐为什么比其他曲奇贵？","丹麦原装进口100%天然黄油成本高。铁罐包装精美送礼有面子。品牌溢价也是因素。"),F("保质期多久？","24个月较长因为铁罐密封性好。开封后建议1月内吃完保持酥脆口感。"),F("真的好吃吗？","黄油香浓郁口感酥脆是公认的高品质曲奇。但甜度偏高不喜欢太甜的可能觉得腻。")],[R("送礼达人",5,"蓝罐曲奇送礼太有面子了！铁罐包装精美长辈都喜欢。黄油味浓郁好吃。"),R("张明",4,"品质好黄油香浓。但168的价格偏贵。自己吃不太划算送礼合适。"),R("李萌",3,"好吃但太甜了吃几块就腻了。配茶或咖啡更好。"),R("王大力",5,"过年送亲戚蓝罐曲奇年年都买。大家都认这个牌子送礼不踩雷。"),R("陈花",2,"908g太多了一个人吃不完开封后一个月有些饼干就受潮了。建议买454g。")],["丹麦蓝罐","食品饮料","饼干","曲奇","黄油","进口","送礼","铁罐","454g","908g"],["节日送礼","长辈探望","下午茶","分享"],["控糖人群","独自食用"],["gift_selection","daily_snack","office_work"]))

