    I.append(("p_food_037","八马茶业安溪铁观音浓香型乌龙茶叶礼盒装500g","八马","茶叶",[S("s_p_food_037_1",{"规格":"125g 罐装"},128),S("s_p_food_037_2",{"规格":"250g 双罐装"},268),S("s_p_food_037_3",{"规格":"500g 礼盒装"},599)],"八马茶业安溪铁观音浓香型正宗安溪产区传统工艺制作。茶叶紧结重实冲泡后兰花香浓郁滋味醇厚回甘。7泡有余香。适合老茶客日常品饮和商务送礼。95°C沸水冲泡每泡30-60秒。",[F("浓香型和清香型有什么区别？","浓香型经过炭焙火香浓郁滋味醇厚。清香型轻发酵轻焙火花香清新。老茶客选浓香新手选清香。"),F("怎么保存？","密封避光阴凉干燥处。开封后建议放冰箱冷藏保鲜。避免和异味物品放一起茶叶易吸味。"),F("送礼合适吗？","500g礼盒装包装精美送礼非常有面子。八马是知名品牌长辈和商务送礼都合适。")],[R("老茶客",5,"八马铁观音品质稳定浓香型兰花香明显回甘好。喝了十几年一直信赖。"),R("张明",4,"茶叶不错但599的礼盒价格偏高。自己喝买罐装更划算。"),R("李萌",3,"还行但浓香型火味偏重我不太喜欢。可能更适合喜欢浓茶的人。"),R("王大力",5,"送领导的八马礼盒很有面子。领导说茶叶好喝。599值得。"),R("陈花",2,"茶叶有点碎完整的叶片不多。599的价格品质应该更好。不太满意。")],["八马","食品饮料","茶叶","铁观音","乌龙茶","浓香","安溪","送礼","125g","250g","500g"],["日常品饮","商务送礼","长辈送礼","茶道"],["不喝茶者","咖啡因敏感"],["daily_snack","gift_selection","office_work"]))

    I.append(("p_food_038","竹叶青茶叶峨眉高山绿茶明前特级雀舌100g","竹叶青","茶叶",[S("s_p_food_038_1",{"规格":"60g"},168),S("s_p_food_038_2",{"规格":"100g"},298),S("s_p_food_038_3",{"规格":"200g 礼盒"},599)],"竹叶青峨眉高山绿茶明前特级雀舌海拔800-1500米高山茶园。清明前采摘一芽一叶鲜嫩。茶汤清澈明亮栗香持久滋味鲜爽回甘。适合绿茶爱好者和商务送礼。80°C水温冲泡避免烫伤嫩芽。",[F("明前茶为什么贵？","清明前采摘气温低生长慢产量少。茶叶最鲜嫩口感最好。一年只有一次明前采摘期。"),F("雀舌是什么等级？","雀舌是竹叶青最高等级全芽头制作外形似雀舌。比论道和品味等级更高。"),F("可以冷泡吗？","可以。冷水泡4-6小时口感更清甜。但热泡栗香更明显。看个人喜好。")],[R("绿茶爱好者",5,"竹叶青雀舌太鲜了！明前茶就是不一样入口鲜爽回甘持久。298的100g值。"),R("张明",4,"品质好栗香明显。但价格确实贵。日常喝买60g的够品鉴。"),R("李萌",3,"好喝但没有想象中惊艳。可能是我对绿茶期待太高。"),R("王大力",5,"送礼选竹叶青礼盒太有品味了。包装精美茶叶品质高。领导很喜欢。"),R("陈花",2,"100g太小了298的价格每克3块钱。虽然好喝但性价比太低。")],["竹叶青","食品饮料","茶叶","绿茶","明前","雀舌","峨眉","高山","60g","100g","200g"],["日常品饮","商务送礼","品鉴","送礼"],["不喝茶者","咖啡因敏感"],["daily_snack","gift_selection","office_work"]))

    I.append(("p_food_039","大益普洱茶熟茶7572标杆茶饼357g云南勐海","大益","茶叶",[S("s_p_food_039_1",{"规格":"150g 小饼"},68),S("s_p_food_039_2",{"规格":"357g 标准饼"},199),S("s_p_food_039_3",{"规格":"357g*7 整提"},899)],"大益7572普洱茶熟茶标杆产品1975年配方传承至今。勐海产区优质原料渥堆发酵工艺成熟。茶汤红浓透亮陈香明显滋味醇厚顺滑。适合普洱入门和老茶客收藏。沸水冲泡洗茶1-2遍。",[F("7572是什么意思？","75年配方7级茶青勐海茶厂（2号厂）出品。是普洱熟茶最经典的标杆产品。"),F("普洱熟茶和生茶有什么区别？","熟茶经过渥堆发酵口感醇厚温和养胃。生茶未发酵口感清爽回甘强刺激大。入门建议熟茶。"),F("可以存放多久？","普洱越陈越香存放得当可以存数十年。通风干燥避光无异味环境。有收藏升值潜力。")],[R("普洱爱好者",5,"7572经典中的经典！陈香明显汤色红浓入口顺滑。199的标准饼性价比很高。"),R("张明",4,"品质稳定大益老牌子值得信赖。但新出厂的需要放1-2年口感更好。"),R("李萌",3,"普洱味道比较特殊不太习惯。可能需要多喝几次才能接受。"),R("王大力",5,"买了整提7饼收藏。大益7572越陈越香过几年喝更好。899一提划算。"),R("陈花",2,"不太喜欢普洱的味道。可能是我不习惯熟茶的陈味。送老爸了他说好喝。")],["大益","食品饮料","茶叶","普洱茶","熟茶","勐海","经典","收藏","150g","357g"],["日常品饮","入门普洱","收藏","送礼"],["不习惯普洱味","绿茶偏好者"],["daily_snack","gift_selection","office_work"]))

