    I.append(("p_food_041","卫龙大面筋辣条经典麻辣味休闲零食网红小吃65g*10包","卫龙","辣条",[S("s_p_food_041_1",{"规格":"65g*5包"},9),S("s_p_food_041_2",{"规格":"65g*10包"},19),S("s_p_food_041_3",{"规格":"混合辣条礼盒"},59)],"卫龙大面筋辣条国民零食经典麻辣味面粉+辣椒油制作口感筋道辣而不燥。多种辣度可选微辣中辣特辣。独立小包装方便携带。适合解馋零食朋友分享。注意辣度肠胃不好者少食。",[F("卫龙辣条卫生吗？","卫龙是辣条行业龙头有完善品控和生产线。通过ISO认证卫生标准有保障。"),F("辣度怎么样？","经典麻辣味中辣大部分人可接受。不能吃辣选微辣版。特辣版辣度高谨慎选择。"),F("热量高吗？","每100g约400千卡一包65g约260千卡。偶尔零食可以不宜天天吃。")],[R("辣条爱好者",5,"卫龙辣条永远的神！筋道辣香太过瘾了。19块10包太划算。"),R("张明",4,"好吃辣度适中。但吃多了嘴巴会辣痛。一次吃2包就够了。"),R("李萌",3,"还行但没有小时候的感觉了。可能是我长大了口味变了。"),R("王大力",5,"聚会拿出来大家抢着吃！国民零食名不虚传。混合礼盒各种口味都有。"),R("陈花",1,"吃完拉肚子了可能肠胃不好不适合吃辣条。虽然好吃但身体受不了。")],["卫龙","食品饮料","零食","辣条","麻辣","面筋","网红","小吃","65g","礼盒"],["追剧零食","聚会分享","解馋","网红零食"],["肠胃不好者","不吃辣者"],["daily_snack","office_work","entertainment"]))

