def main():
    with open(DATA_FILE, "r", encoding="utf-8") as f:
        products = json.load(f)
    original = len(products)
    print(f"Original product count: {original}")

    digital = build("数码电子", "digital", gen_digital())
    beauty = build("美妆护肤", "beauty", gen_beauty())
    clothing = build("服饰运动", "clothing", gen_clothing())
    food = build("食品饮料", "food", gen_food())

    new_products = digital + beauty + clothing + food
    products.extend(new_products)

    with open(DATA_FILE, "w", encoding="utf-8") as f:
        json.dump(products, f, ensure_ascii=False, indent=2)

    print(f"\n=== Expansion Summary ===")
    print(f"Digital products added:  {len(digital)}")
    print(f"Beauty products added:   {len(beauty)}")
    print(f"Clothing products added: {len(clothing)}")
    print(f"Food products added:     {len(food)}")
    print(f"Total new products:      {len(new_products)}")
    print(f"Total products in file:  {len(products)}")
    print(f"File saved to: {DATA_FILE}")

if __name__ == "__main__":
    main()
